<script setup lang="ts">
import{computed,onMounted,reactive,ref}from'vue';import{Edit3,KeyRound,Plus,RefreshCw,Save,Search,X}from'@lucide/vue';import{useI18n}from'vue-i18n';import{createOperatorCustomerKey,createOperatorResource,listOperatorResource,updateOperatorResource}from'@/api/operator';import type{OperatorCustomer,OperatorCustomerGroup,OperatorPlan}from'@/types';const{t}=useI18n();const items=ref<OperatorCustomer[]>([]),groups=ref<OperatorCustomerGroup[]>([]),plans=ref<OperatorPlan[]>([]),query=ref(''),error=ref(''),message=ref(''),modal=ref(false),keyModal=ref(false),editing=ref<OperatorCustomer|null>(null),keyCustomer=ref<OperatorCustomer|null>(null),createdKey=ref('');const form=reactive({name:'',email:'',group_id:'',plan_id:'',status:'active',credit_cents:0,notes:''});const keyForm=reactive({name:'',policy_id:'',model_allowlist:['gpt-5'],qps_limit:0,monthly_token_limit:0,expires_at:'',key_type:'customer',customer_id:''});const filtered=computed(()=>items.value.filter(v=>!query.value||`${v.name} ${v.email}`.toLowerCase().includes(query.value.toLowerCase())));const groupName=(id:string)=>groups.value.find(v=>v.id===id)?.name||'-';const planName=(id:string)=>plans.value.find(v=>v.id===id)?.name||'-';async function load(){[items.value,groups.value,plans.value]=await Promise.all([listOperatorResource('customers') as Promise<OperatorCustomer[]>,listOperatorResource('customer-groups') as Promise<OperatorCustomerGroup[]>,listOperatorResource('plans') as Promise<OperatorPlan[]>])}function openCreate(){editing.value=null;Object.assign(form,{name:'',email:'',group_id:'',plan_id:'',status:'active',credit_cents:0,notes:''});modal.value=true}function openEdit(v:OperatorCustomer){editing.value=v;Object.assign(form,v);modal.value=true}async function save(){try{if(editing.value)await updateOperatorResource('customers',editing.value.id,{...form});else await createOperatorResource('customers',{...form});modal.value=false;await load()}catch(e){error.value=e instanceof Error?e.message:t('common.failed')}}function openKey(v:OperatorCustomer){keyCustomer.value=v;createdKey.value='';keyForm.name=`${v.name} key`;keyForm.customer_id=v.id;keyModal.value=true}async function createKey(){if(!keyCustomer.value)return;try{const result=await createOperatorCustomerKey(keyCustomer.value.id,{...keyForm});createdKey.value=result.key;message.value=t('operatorDomain.keyCreated');await load()}catch(e){error.value=e instanceof Error?e.message:t('common.failed')}}onMounted(load)
</script>
<template><main class="content crud-page"><section class="page-header"><div><h1>{{t('operatorDomain.customers')}}</h1><p>{{t('operatorDomain.customersHelp')}}</p></div><button class="button" @click="openCreate"><Plus :size="17"/>{{t('operatorDomain.newCustomer')}}</button></section><section class="table-toolbar"><label class="search-box"><Search :size="17"/><input v-model="query" :placeholder="t('operatorCrud.search')"/></label><button class="button secondary" @click="load"><RefreshCw :size="17"/>{{t('common.refresh')}}</button></section><div v-if="message" class="notice success">{{message}}</div><div v-if="error" class="notice">{{error}}</div><section class="panel table-panel"><div class="panel-body table-scroll"><table class="data-table crud-table"><thead><tr><th>{{t('operatorDomain.customer')}}</th><th>{{t('operatorDomain.group')}}</th><th>{{t('operatorDomain.plan')}}</th><th>{{t('operatorDomain.balance')}}</th><th>{{t('operatorDomain.credit')}}</th><th>{{t('providers.status')}}</th><th>{{t('common.actions')}}</th></tr></thead><tbody><tr v-for="v in filtered" :key="v.id"><td><strong>{{v.name}}</strong><span>{{v.email||v.id}}</span></td><td>{{groupName(v.group_id)}}</td><td>{{planName(v.plan_id)}}</td><td>{{(v.balance_cents/100).toFixed(2)}}</td><td>{{(v.credit_cents/100).toFixed(2)}}</td><td><span class="pill" :class="v.status==='active'?'status-success':'status-warning'">{{v.status}}</span></td><td class="table-actions"><button class="icon-button" :title="t('common.edit')" @click="openEdit(v)"><Edit3 :size="16"/></button><button class="icon-button" :title="t('operatorDomain.createKey')" @click="openKey(v)"><KeyRound :size="16"/></button></td></tr><tr v-if="!filtered.length"><td colspan="7" class="empty-cell"></td></tr></tbody></table></div></section><div v-if="modal" class="modal-backdrop"><form class="modal-card" @submit.prevent="save"><header class="modal-header"><h2>{{editing?t('common.edit'):t('operatorDomain.newCustomer')}}</h2><button class="icon-button" type="button" @click="modal=false"><X :size="18"/></button></header><div class="modal-body form-grid"><div class="field"><label>{{t('operatorDomain.name')}}</label><input v-model="form.name" required/></div><div class="field"><label>Email</label><input v-model="form.email" type="email"/></div><div class="field"><label>{{t('operatorDomain.group')}}</label><select v-model="form.group_id"><option value="">-</option><option v-for="v in groups" :key="v.id" :value="v.id">{{v.name}}</option></select></div><div class="field"><label>{{t('operatorDomain.plan')}}</label><select v-model="form.plan_id"><option value="">-</option><option v-for="v in plans" :key="v.id" :value="v.id">{{v.name}}</option></select></div><div class="field"><label>{{t('operatorDomain.credit')}}</label><input v-model.number="form.credit_cents" type="number" min="0"/></div><div class="field"><label>{{t('providers.status')}}</label><select v-model="form.status"><option value="active">active</option><option value="disabled">disabled</option></select></div><div class="field field-wide"><label>{{t('operatorDomain.notes')}}</label><textarea v-model="form.notes" rows="3"/></div></div><footer class="modal-footer"><button class="button secondary" type="button" @click="modal=false">{{t('common.cancel')}}</button><button class="button" type="submit"><Save :size="17"/>{{t('common.save')}}</button></footer></form></div><div v-if="keyModal" class="modal-backdrop"><form class="modal-card" @submit.prevent="createKey"><header class="modal-header"><h2>{{t('operatorDomain.createKey')}}</h2><button class="icon-button" type="button" @click="keyModal=false"><X :size="18"/></button></header><div class="modal-body form-grid"><div class="field"><label>{{t('apiKeys.name')}}</label><input v-model="keyForm.name" required/></div><div class="field"><label>{{t('apiKeys.models')}}</label><input :value="keyForm.model_allowlist.join(',')" @input="keyForm.model_allowlist=($event.target as HTMLInputElement).value.split(',').map(v=>v.trim()).filter(Boolean)"/></div><div class="field"><label>QPS</label><input v-model.number="keyForm.qps_limit" type="number" min="0"/></div><div v-if="createdKey" class="field field-wide"><label>{{t('operatorDomain.createdKey')}}</label><code>{{createdKey}}</code></div></div><footer class="modal-footer"><button class="button secondary" type="button" @click="keyModal=false">{{t('common.cancel')}}</button><button class="button" type="submit"><KeyRound :size="17"/>{{t('operatorDomain.createKey')}}</button></footer></form></div></main></template>
